var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐엑- 헥-","JPN":"はあ……ふえっ……","ENG":"*Huff...* *Huff...*","TWN":"呼，呼。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"후아… 이 정도면 따돌린 것 같은데요?","JPN":"ふう……これくらいなら引き離せましたよね？","ENG":"Whew... I think we lost them.","TWN":"呼…應該安全了吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"큭, 분하다. 눈앞에 보물을 잔뜩 두고 도망치는 신세라니.","JPN":"くっ、悔しい。宝を目の前にして逃げるなんて。","ENG":"Kgh, I can't believe this. I have to run away from all that treasure right in front of my eyes.","TWN":"真是生氣，寶藏就近在眼前，我們卻只能逃。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아까 전엔 보물에 하나도 관심 없다며?","JPN":"さっきは宝に興味はないと言ってなかったか？","ENG":"Didn't you say you weren't interested in the treasure?","TWN":"你之前還說對寶藏不感興趣？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"관심 없을 리 있겠냐? 이래봬도 난 해적이라고.","JPN":"そんなわけないだろう？　こう見えても、俺は海賊なんだよ。","ENG":"You believed that? I'm still a pirate, you know.","TWN":"怎麼可能不感興趣？畢竟我是個海盜。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"저기… 저희는 이제 어쩌면 좋죠?","JPN":"あの……俺たちはこれからどうしたらいいですか？","ENG":"Err... What do we do now?","TWN":"那個…我們現在怎麼辦？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐야? 넌 또 왜 따라왔어? 애초에 우리랑 같은 해적도 아니잖아?","JPN":"何だ？　お前、なんでまたついて来たんだよ。だいたい、俺たちと同じ海賊でもないだろう？","ENG":"Huh? Why are you following us? You're not even a pirate like the rest of us.","TWN":"搞什麼？你怎麼又跟上來啦？你又不是海盜！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"그, 그럴 수가…","JPN":"そ、そんな……","ENG":"B-but...","TWN":"怎…怎麼會…"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어쩜! 생각이 짧네요, 터커 씨!","JPN":"もう！　浅はかですね、ターカーさん！","ENG":"Oh, Tucker! How can you be so shortsighted?","TWN":"嘖嘖，你的眼光太短淺啦，塔克！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"헌터들과 마주쳤을 때 협상카드로 쓸 인질이 하나쯤은 있어야죠!","JPN":"ハンターと出くわした時に交渉で使える人質が一人くらいはいないと！","ENG":"We need a hostage to use as a bargaining chip if we run into more hunters!","TWN":"我們要抓一個來當之後遇到獵人時的談判籌碼吧！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"예전에 샌님처럼 생겼다고 놀린 건 사과할게, 탈리. 네가 우리 중에 제일 해적답다 야.","JPN":"前に頭でっかちってからかったの、謝っておくよ、タリー。お前が俺たちの中で一番海賊っぽいな。","ENG":"I'm sorry for teasing you about being a dweeb before, Tallie. You're the most pirate-like out of all of us.","TWN":"塔莉，我為之前取笑你像傻子而道歉，你是我們當中最像海盜的人。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"앗?","JPN":"あっ？","ENG":"Oh?","TWN":"蛤？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저기 좀 보세요! 숲 속에 커다란 건물이 있어요!","JPN":"あそこを見てください！　森の中に大きな建物がありますわ！","ENG":"Look over there! There's a huge building within the forest!","TWN":"看，樹林裡有間大房子！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저건… 해적 요새네.","JPN":"あれは……海賊の要塞だな。","ENG":"That's... a pirate fortress.","TWN":"那是…海盜堡壘。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"사람은 살지 않는 것 같네요.","JPN":"人は住んでないみたいですね。","ENG":"It doesn't look like anyone's still living there.","TWN":"這裡似乎沒有人居住。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"오랫동안 버려졌구만. 사람 흔적은 없고 거의 터만 남았어.","JPN":"長い間打ち捨てられてたんだ。人の形跡はないし、ほとんど基礎だけ残ってる。","ENG":"It's been abandoned for a long time. There are no signs of life.","TWN":"看來這裡已經廢棄許久，沒有任何生活的跡象，只有一片廢墟。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐음- 해골 같은 건 하나도 안 보여요. 사고가 있었던 건 아닌가봐요.","JPN":"ふーむ、骸骨とかは一つも見当たりません。事故があったわけではなさそうです。","ENG":"Hmm... I don't see any skeletons. I guess there wasn't an accident over here.","TWN":"嗯，我沒看到任何骷髏頭或其他東西，是不是發生過什麼意外？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯…？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"이것 좀 보세요. 여기에도 금화가 떨어져 있네요.","JPN":"これを見てください。ここにも金貨が落ちてますね。","ENG":"Check this out. There's gold over here too.","TWN":"看看這個，這裡也有一枚金幣。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"쳇, 아쉬운 대로 그거라도 일단 챙기자고.","JPN":"ちっ、残念だけどそれだけでも拾っておこう。","ENG":"Tch. Let's at least take this.","TWN":"嘖，有一點算一點。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};